from typing import Any, Dict, List, Optional, Literal

from pydantic import BaseModel, Field

from .base import AgentCapability, AgentMetadataBase, AgentInputBase, AgentOutputBase


class FrontendDebuggerAgentInput(AgentInputBase):
    constraints: Dict[str, Any] = Field(default_factory=dict, description="Execution constraints")
    context: Optional[str] = Field(None, description="Additional context")
    parameters: Dict[str, Any] = Field(default_factory=dict, description="Structured parameters")
    resources: List[str] = Field(default_factory=list, description="Relevant resources")
    task: str = Field(..., description="Primary task to execute")


class FrontendDebuggerAgentOutput(AgentOutputBase):
    artifacts: List[str] = Field(default_factory=list, description="Artifact identifiers or paths")
    data: Dict[str, Any] = Field(default_factory=dict, description="Structured output data")
    errors: List[str] = Field(default_factory=list, description="Errors, if any")
    status: Literal["success", "failed", "partial"] = Field(..., description="Execution status")
    summary: str = Field(..., description="Concise summary of results")


class FrontendDebuggerAgentMetadata(AgentMetadataBase):
    agent_id: str = "frontend-debugger-agent"
    name: str = "frontend-debugger-agent"
    description: str = "MUST BE USED to debug frontend issues including React errors, browser extension conflicts, custom element collisions, WebSocket connection failures, and JavaScript runtime errors. Provides comprehensive diagnostic and resolution capabilities for modern web applications."
